using Microsoft.AspNetCore.Authorization; using Microsoft.AspNetCore.Mvc; using System.Security.Claims; using Valora.Application.Contracts; using Valora.Application.DTOs;
namespace Valora.Api.Controllers; [Authorize][ApiController] public sealed class EmailController(IEmailTemplateService templates,IEmailQueueService queue,IEmailSenderService sender,IEmailStatusService status):ControllerBase{ Guid Org=>Guid.Parse(User.FindFirstValue("organization_id")??Guid.Empty.ToString()); [HttpGet("/email/templates")] public async Task<IActionResult> Templates()=>Ok(new{ok=true,data=await templates.ListAsync(Org)}); [HttpPost("/email/templates")] public async Task<IActionResult> Create([FromBody]UpsertEmailTemplateRequest r)=>Ok(new{ok=true,template=await templates.UpsertAsync(null,r)}); [HttpPut("/email/templates/{id:guid}")] public async Task<IActionResult> Put(Guid id,[FromBody]UpsertEmailTemplateRequest r)=>Ok(new{ok=true,template=await templates.UpsertAsync(id,r)}); [HttpGet("/email/jobs")] public async Task<IActionResult> Jobs()=>Ok(new{ok=true,status="safe_metadata_only"}); [HttpPost("/email/jobs/{id:guid}/retry")] public async Task<IActionResult> Retry(Guid id)=>Ok(new{ok=true,job=await queue.RetryAsync(id)}); [HttpPost("/email/jobs/process")] public async Task<IActionResult> Process()=>Ok(new{ok=true,processed=await sender.ProcessAsync()}); [HttpGet("/email/status")] public async Task<IActionResult> Status()=>Ok(new{ok=true,status=await status.GetAsync(Org)}); [HttpPost("/responses/{responseId:guid}/send-result-email")] public async Task<IActionResult> Result(Guid responseId,[FromBody]Dictionary<string,string> b)=>Ok(new{ok=true,job=await queue.QueueResultAsync(Org,responseId,b.GetValueOrDefault("toEmail")??"dev@example.com")}); [HttpPost("/surveys/{surveyId:guid}/send-invites")] public async Task<IActionResult> Invite(Guid surveyId,[FromBody]Dictionary<string,string> b)=>Ok(new{ok=true,job=await queue.QueueInviteAsync(Org,surveyId,b.GetValueOrDefault("toEmail")??"dev@example.com")});}
